INSERT
  INTO TB_ARVU_PLAC_M
     (
       PLAC_ID
     , PLAC_NM
     , EXTL_PLAC_ID
     , SORC_DVCD
     , CTGR_DVCD
     , ADDR
     , TEL_NO
     , LTTD
     , LGTD
     , REG_ID
     , REG_DTM
     , CHNG_ID
     , CHNG_DTM
     )
VALUES
     (
       NEXTVAL(SEQ_ARVU_PLAC_ID)
     , #{placNm}
     , #{extlPlacId}
     , #{sorcDvcd}
     , #{ctgrDvcd}
     , #{addr}
     , #{telNo}
     , #{lttd}
     , #{lgtd}
     , 'SYSTEM'
     , SUBSTR(DATE_FORMAT(NOW(3), '%Y%m%d%H%i%s%f'), 1, 17)
     , 'SYSTEM'
     , SUBSTR(DATE_FORMAT(NOW(3), '%Y%m%d%H%i%s%f'), 1, 17)
     )
